fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    let mod_val = 1073741827; // 10^9 + 7
    let n = nums.len();

    // Apply each query
    for query in queries {
        let li = query[0];
        let ri = query[1];
        let ki = query[2];
        let vi = query[3];

        let mut idx = li;
        while idx <= ri {
            nums[idx as usize] = (nums[idx as usize] * vi) % mod_val;
            idx += ki;
        }
    }

    // Compute the XOR of all elements
    let mut xor_result = 0;
    for num in nums {
        xor_result ^= num;
    }

    xor_result
}
